private fun validateConstraints(): Boolean { if (isCWT) return true if (pcmData == null) return false val maxLevel = (log2(pcmData!!.size.toDouble())).toInt() - 2 if (decompositionLevel > maxLevel) { decompositionLevel = maxLevel.coerceAtLeast(1) sliderLevel.value = decompositionLevel.toFloat() return false } return true }
