waveletView = findViewById(R.id.waveletView) familySpinner = findViewById(R.id.waveletFamilySpinner) boundarySpinner = findViewById(R.id.waveletBoundarySpinner) colorSpinner = findViewById(R.id.waveletColorSpinner) checkSoft = findViewById(R.id.checkSoftThresh) checkWPT = findViewById(R.id.checkWPT) checkLog = findViewById(R.id.checkLogScale) checkLocalNorm = findViewById(R.id.checkLocalNorm) checkReconstruct = findViewById(R.id.checkReconstruct) checkCWT = findViewById(R.id.checkCWT) sliderOrder = findViewById(R.id.sliderOrder) sliderLevel = findViewById(R.id.sliderLevel) sliderSampling = findViewById(R.id.sliderSampling) sliderThreshold = findViewById(R.id.sliderThreshold)
